import type { AdapterCapabilities, AdapterCategory, HealthMetrics } from '../../types/adapter';
import type { TokenSecurityScore, SecurityRiskLevel } from '../../types/security';
import { RateLimiter } from '../../rate-limiter/rate-limiter';
import type { GoPlusApiResponse, GoPlusTokenSecurityResult, GoPlusRawTokenSecurity } from './goplus-types';

const API_BASE = 'https://api.gopluslabs.com/api/v1';

/** Cache entry with expiration. */
interface CacheEntry<T> {
  data: T;
  expiresAt: number;
}

/** Supported chain name to GoPlus chain ID mapping. */
const CHAIN_ID_MAP: Readonly<Record<string, number>> = {
  ethereum: 1,
  bsc: 56,
  polygon: 137,
  arbitrum: 42161,
  optimism: 10,
  base: 8453,
  avalanche: 43114,
};

/**
 * GoPlus adapter for token security analysis.
 *
 * Provides on-chain security scoring including honeypot detection, tax analysis,
 * holder concentration, and contract verification status. Uses GoPlus Labs'
 * public API — no authentication required.
 *
 * Security data is cached for 5 minutes per address since on-chain security
 * properties change infrequently. Risk levels are derived from a deterministic
 * ruleset applied to raw contract analysis results.
 */
export class GoPlusAdapter {
  readonly exchangeId = 'goplus' as const;
  readonly displayName = 'GoPlus';
  readonly category: AdapterCategory = 'data-provider';
  readonly capabilities: AdapterCapabilities = {
    realtime: false,
    historicalDepth: 'none',
    orderbook: false,
    trades: false,
    ohlcv: false,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: false,
    onChainMetrics: true,
    authenticated: false,
  };

  private readonly rateLimiter: RateLimiter;
  private readonly cache = new Map<string, CacheEntry<TokenSecurityScore>>();

  private static readonly CACHE_TTL_MS = 300_000; // 5 minutes

  constructor() {
    this.rateLimiter = new RateLimiter('goplus', {
      maxTokens: 30,
      windowMs: 60_000,
      queueExcess: true,
      maxQueueDepth: 20,
    });
  }

  getHealthMetrics(): HealthMetrics {
    return {
      connected: true,
      latencyMs: 0,
      messagesPerSecond: 0,
      uptimePercent: 100,
      lastMessageAt: 0,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  /**
   * Analyze the security of a single token.
   *
   * @param address - Token contract address.
   * @param chain - Chain name (e.g., "ethereum", "bsc", "polygon").
   * @throws If the chain is unsupported or the API returns an error.
   */
  async getTokenSecurity(address: string, chain: string): Promise<TokenSecurityScore> {
    const normalizedAddress = address.toLowerCase();
    const normalizedChain = chain.toLowerCase();
    const cacheKey = `${normalizedChain}:${normalizedAddress}`;

    const cached = this.getCached(cacheKey);
    if (cached !== undefined) return cached;

    const chainId = this.resolveChainId(normalizedChain);
    const result = await this.fetchTokenSecurity(chainId, normalizedAddress);

    const tokenData = result[normalizedAddress];
    if (!tokenData) {
      throw new Error(`GoPlus returned no data for address ${address} on ${chain}`);
    }

    const score = this.normalizeTokenSecurity(tokenData, normalizedAddress, normalizedChain);
    this.setCache(cacheKey, score, GoPlusAdapter.CACHE_TTL_MS);
    return score;
  }

  /**
   * Analyze the security of multiple tokens in batch.
   *
   * Tokens are grouped by chain to minimize API calls. Results maintain
   * the same order as the input array.
   *
   * @param tokens - Array of token address/chain pairs.
   */
  async getTokenSecurityBatch(
    tokens: Array<{ address: string; chain: string }>,
  ): Promise<TokenSecurityScore[]> {
    // Group tokens by chain for efficient batching
    const byChain = new Map<string, Array<{ address: string; index: number }>>();

    for (let i = 0; i < tokens.length; i++) {
      const token = tokens[i]!;
      const chain = token.chain.toLowerCase();
      const group = byChain.get(chain);
      if (group) {
        group.push({ address: token.address.toLowerCase(), index: i });
      } else {
        byChain.set(chain, [{ address: token.address.toLowerCase(), index: i }]);
      }
    }

    const results: TokenSecurityScore[] = new Array(tokens.length);

    for (const [chain, group] of byChain) {
      // Check cache first and identify which addresses need fetching
      const uncached: Array<{ address: string; index: number }> = [];

      for (const item of group) {
        const cacheKey = `${chain}:${item.address}`;
        const cached = this.getCached(cacheKey);
        if (cached !== undefined) {
          results[item.index] = cached;
        } else {
          uncached.push(item);
        }
      }

      if (uncached.length === 0) continue;

      const chainId = this.resolveChainId(chain);
      const addresses = uncached.map((u) => u.address).join(',');
      const response = await this.fetchTokenSecurity(chainId, addresses);

      for (const item of uncached) {
        const tokenData = response[item.address];
        if (!tokenData) {
          throw new Error(`GoPlus returned no data for address ${item.address} on ${chain}`);
        }
        const score = this.normalizeTokenSecurity(tokenData, item.address, chain);
        this.setCache(`${chain}:${item.address}`, score, GoPlusAdapter.CACHE_TTL_MS);
        results[item.index] = score;
      }
    }

    return results;
  }

  /**
   * Resolve a chain name to its GoPlus chain ID.
   *
   * @throws If the chain is not supported.
   */
  private resolveChainId(chain: string): number {
    const chainId = CHAIN_ID_MAP[chain];
    if (chainId === undefined) {
      const supported = Object.keys(CHAIN_ID_MAP).join(', ');
      throw new Error(`Unsupported chain "${chain}". Supported chains: ${supported}`);
    }
    return chainId;
  }

  private async fetchTokenSecurity(chainId: number, addresses: string): Promise<GoPlusTokenSecurityResult> {
    await this.rateLimiter.acquire();

    const url = `${API_BASE}/token_security/${chainId}?contract_addresses=${encodeURIComponent(addresses)}`;
    const response = await fetch(url, {
      method: 'GET',
      headers: { Accept: 'application/json' },
    });

    if (!response.ok) {
      const body = await response.text().catch(() => '');
      throw new Error(
        `GoPlus API error: ${response.status} ${response.statusText}${body ? ` — ${body}` : ''}`,
      );
    }

    const envelope = (await response.json()) as GoPlusApiResponse<GoPlusTokenSecurityResult>;

    if (envelope.code !== 1) {
      throw new Error(`GoPlus API error: ${envelope.message} (code: ${envelope.code})`);
    }

    return envelope.result;
  }

  private normalizeTokenSecurity(
    raw: GoPlusRawTokenSecurity,
    address: string,
    chain: string,
  ): TokenSecurityScore {
    const isHoneypot = raw.is_honeypot === '1';
    const isOpenSource = raw.is_open_source === '1';
    const isProxy = raw.is_proxy === '1';
    const buyTax = this.parsePercent(raw.buy_tax);
    const sellTax = this.parsePercent(raw.sell_tax);
    const holderCount = this.parseInt(raw.holder_count);
    const top10HolderPercent = this.computeTop10HolderPercent(raw);

    const overallRisk = this.deriveRiskLevel({
      isHoneypot,
      isOpenSource,
      isProxy,
      buyTax,
      sellTax,
      top10HolderPercent,
    });

    return {
      address,
      chain,
      isHoneypot,
      isOpenSource,
      isProxy,
      buyTax,
      sellTax,
      holderCount,
      top10HolderPercent,
      overallRisk,
      timestamp: Date.now(),
    };
  }

  /**
   * Derive the overall risk level from token security attributes.
   *
   * Evaluation order matters — the first matching rule wins:
   * 1. Critical: honeypot OR sell tax > 50%
   * 2. High: buy/sell tax > 10% OR top 10 holders > 80% OR not open source
   * 3. Medium: buy/sell tax > 5% OR top 10 holders > 60% OR proxy contract
   * 4. Low: everything else
   */
  private deriveRiskLevel(attrs: {
    isHoneypot: boolean;
    isOpenSource: boolean;
    isProxy: boolean;
    buyTax: number;
    sellTax: number;
    top10HolderPercent: number;
  }): SecurityRiskLevel {
    if (attrs.isHoneypot || attrs.sellTax > 50) {
      return 'critical';
    }

    if (attrs.buyTax > 10 || attrs.sellTax > 10 || attrs.top10HolderPercent > 80 || !attrs.isOpenSource) {
      return 'high';
    }

    if (attrs.buyTax > 5 || attrs.sellTax > 5 || attrs.top10HolderPercent > 60 || attrs.isProxy) {
      return 'medium';
    }

    return 'low';
  }

  private computeTop10HolderPercent(raw: GoPlusRawTokenSecurity): number {
    if (!raw.holders || raw.holders.length === 0) return 0;

    const sorted = [...raw.holders]
      .sort((a, b) => parseFloat(b.percent) - parseFloat(a.percent))
      .slice(0, 10);

    return sorted.reduce((sum, h) => sum + parseFloat(h.percent) * 100, 0);
  }

  private parsePercent(value: string | undefined): number {
    if (value === undefined || value === '') return 0;
    const parsed = parseFloat(value);
    if (isNaN(parsed)) return 0;
    // GoPlus returns tax as a decimal (0.05 = 5%), convert to percentage
    return parsed * 100;
  }

  private parseInt(value: string | undefined): number {
    if (value === undefined || value === '') return 0;
    const parsed = Number.parseInt(value, 10);
    return isNaN(parsed) ? 0 : parsed;
  }

  private getCached(key: string): TokenSecurityScore | undefined {
    const entry = this.cache.get(key);
    if (!entry) return undefined;
    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(key);
      return undefined;
    }
    return entry.data;
  }

  private setCache(key: string, data: TokenSecurityScore, ttlMs: number): void {
    this.cache.set(key, { data, expiresAt: Date.now() + ttlMs });
  }
}
